// UGO Landing Page - WOW.js Animation Library

// ===== WOW.JS ===== */
window.WOW = function(options) {
    this.options = options || {};
    this.boxClass = this.options.boxClass || 'wow';
    this.animateClass = this.options.animateClass || 'animate__animated';
    this.offset = this.options.offset || 0;
    this.mobile = this.options.mobile !== false;
    this.live = this.options.live !== false;
    
    this.init = function() {
        const wowElements = document.querySelectorAll('.' + this.boxClass);
        
        if (!this.mobile && window.innerWidth <= 768) {
            // Remove animation classes on mobile if disabled
            wowElements.forEach(element => {
                element.classList.remove(this.boxClass);
            });
            return;
        }
        
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    const element = entry.target;
                    
                    // Add animation classes
                    element.classList.add(this.animateClass);
                    
                    // Get animation name from data-wow attribute
                    const animationName = element.getAttribute('data-wow-animation');
                    if (animationName) {
                        element.classList.add(animationName);
                    }
                    
                    // Get animation duration
                    const duration = element.getAttribute('data-wow-duration');
                    if (duration) {
                        element.style.animationDuration = duration;
                    }
                    
                    // Get animation delay
                    const delay = element.getAttribute('data-wow-delay');
                    if (delay) {
                        element.style.animationDelay = delay;
                    }
                    
                    // Get animation iteration count
                    const iteration = element.getAttribute('data-wow-iteration');
                    if (iteration) {
                        element.style.animationIterationCount = iteration;
                    }
                    
                    // Remove wow class to prevent re-triggering
                    element.classList.remove(this.boxClass);
                    
                    // Stop observing this element
                    observer.unobserve(element);
                }
            });
        }, {
            threshold: 0.1,
            rootMargin: this.offset + 'px'
        });
        
        wowElements.forEach(element => {
            observer.observe(element);
        });
    };
    
    // Auto-initialize
    this.init();
};

// ===== ANIMATION CLASSES ===== */
const animationClasses = [
    'fadeIn', 'fadeInUp', 'fadeInDown', 'fadeInLeft', 'fadeInRight',
    'fadeOut', 'fadeOutUp', 'fadeOutDown', 'fadeOutLeft', 'fadeOutRight',
    'slideInUp', 'slideInDown', 'slideInLeft', 'slideInRight',
    'slideOutUp', 'slideOutDown', 'slideOutLeft', 'slideOutRight',
    'bounceIn', 'bounceInUp', 'bounceInDown', 'bounceInLeft', 'bounceInRight',
    'bounceOut', 'bounceOutUp', 'bounceOutDown', 'bounceOutLeft', 'bounceOutRight',
    'zoomIn', 'zoomInUp', 'zoomInDown', 'zoomInLeft', 'zoomInRight',
    'zoomOut', 'zoomOutUp', 'zoomOutDown', 'zoomOutLeft', 'zoomOutRight',
    'rotateIn', 'rotateInDownLeft', 'rotateInDownRight', 'rotateInUpLeft', 'rotateInUpRight',
    'rotateOut', 'rotateOutDownLeft', 'rotateOutDownRight', 'rotateOutUpLeft', 'rotateOutUpRight',
    'flipInX', 'flipInY', 'flipOutX', 'flipOutY',
    'lightSpeedIn', 'lightSpeedOut',
    'hinge', 'rollIn', 'rollOut'
];

// ===== ADD ANIMATION CLASSES TO DOCUMENT ===== */
animationClasses.forEach(className => {
    // Add to animate__animated class if not exists
    if (!document.querySelector(`.animate__${className}`)) {
        const style = document.createElement('style');
        style.textContent = `
            .animate__${className} {
                animation-name: ${className};
            }
        `;
        document.head.appendChild(style);
    }
});

// ===== KEYFRAME ANIMATIONS ===== */
const keyframes = `
@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translate3d(0, 30px, 0);
    }
    to {
        opacity: 1;
        transform: translate3d(0, 0, 0);
    }
}

@keyframes fadeInDown {
    from {
        opacity: 0;
        transform: translate3d(0, -30px, 0);
    }
    to {
        opacity: 1;
        transform: translate3d(0, 0, 0);
    }
}

@keyframes fadeInLeft {
    from {
        opacity: 0;
        transform: translate3d(-30px, 0, 0);
    }
    to {
        opacity: 1;
        transform: translate3d(0, 0, 0);
    }
}

@keyframes fadeInRight {
    from {
        opacity: 0;
        transform: translate3d(30px, 0, 0);
    }
    to {
        opacity: 1;
        transform: translate3d(0, 0, 0);
    }
}

@keyframes slideInUp {
    from {
        transform: translate3d(0, 100%, 0);
        visibility: visible;
    }
    to {
        transform: translate3d(0, 0, 0);
    }
}

@keyframes slideInDown {
    from {
        transform: translate3d(0, -100%, 0);
        visibility: visible;
    }
    to {
        transform: translate3d(0, 0, 0);
    }
}

@keyframes slideInLeft {
    from {
        transform: translate3d(-100%, 0, 0);
        visibility: visible;
    }
    to {
        transform: translate3d(0, 0, 0);
    }
}

@keyframes slideInRight {
    from {
        transform: translate3d(100%, 0, 0);
        visibility: visible;
    }
    to {
        transform: translate3d(0, 0, 0);
    }
}

@keyframes bounceIn {
    0%, 20%, 40%, 60%, 80%, 100% {
        transition-timing-function: cubic-bezier(0.215, 0.610, 0.355, 1.000);
    }
    0% {
        opacity: 0;
        transform: scale3d(0.3, 0.3, 0.3);
    }
    20% {
        transform: scale3d(1.1, 1.1, 1.1);
    }
    40% {
        transform: scale3d(0.9, 0.9, 0.9);
    }
    60% {
        opacity: 1;
        transform: scale3d(1.03, 1.03, 1.03);
    }
    80% {
        transform: scale3d(0.97, 0.97, 0.97);
    }
    100% {
        opacity: 1;
        transform: scale3d(1, 1, 1);
    }
}

@keyframes zoomIn {
    from {
        opacity: 0;
        transform: scale3d(0.3, 0.3, 0.3);
    }
    50% {
        opacity: 1;
    }
}

@keyframes rotateIn {
    from {
        transform: rotate3d(0, 0, 1, -200deg);
        opacity: 0;
    }
    to {
        transform: translate3d(0, 0, 0);
        opacity: 1;
    }
}

@keyframes flipInX {
    from {
        transform: perspective(400px) rotate3d(1, 0, 0, 90deg);
        opacity: 0;
    }
    40% {
        transform: perspective(400px) rotate3d(1, 0, 0, -20deg);
    }
    60% {
        transform: perspective(400px) rotate3d(1, 0, 0, 10deg);
        opacity: 1;
    }
    80% {
        transform: perspective(400px) rotate3d(1, 0, 0, -5deg);
    }
    to {
        transform: perspective(400px);
    }
}

@keyframes lightSpeedIn {
    from {
        transform: translate3d(100%, 0, 0) skewX(-30deg);
        opacity: 0;
    }
    60% {
        transform: skewX(20deg);
        opacity: 1;
    }
    80% {
        transform: skewX(-5deg);
        opacity: 1;
    }
    to {
        transform: translate3d(0, 0, 0);
    }
}

@keyframes rollIn {
    from {
        opacity: 0;
        transform: translate3d(-100%, 0, 0) rotate3d(0, 0, 1, -120deg);
    }
    to {
        opacity: 1;
        transform: translate3d(0, 0, 0);
    }
}
`;

// Add keyframes to document
const styleSheet = document.createElement('style');
styleSheet.textContent = keyframes;
document.head.appendChild(styleSheet);

// ===== AUTO-INIT ===== */
document.addEventListener('DOMContentLoaded', function() {
    new WOW();
});

// ===== EXPORT ===== */
if (typeof module !== 'undefined' && module.exports) {
    module.exports = WOW;
}
